import axios from "axios"
const url = "http://localhost:8080/api/robotApi";

//חיפוש כל הרובוטים
export const getAll = async() => {
    try {
        const {data}=await axios.get(`${url}/getAllRobots`)
        return data;
    }
    catch(e) {
        console.log(e)
    }
}

//חיפוש רובוט לפי קוד
export const getById = async(id) => {
        try {
        const {data}=await axios.get(`${url}/getRobotById/${id}`)
        return data;
    }
    catch(e) {
        console.log(e)
    }

}

//הוספת רובוט
export const addRobot = async(robot) => {
    try {
        const {data}=await axios.post(`${url}/postRobot`,robot)
        return data;
    }
    catch(e) {
        console.log(e)
    }
}
// התיקון הקטן: הוספת /image/ לנתיב
export const getImageUrl = (img) => {
    // הדפסה לבדיקה - פתחי את ה-F12 בדפדפן כדי לראות מה מודפס
    console.log("מה הגיע לפונקציה?", img);

    // בדיקה שהערך קיים והוא בכלל טקסט
    if (!img || typeof img !== 'string') {
        return "https://via.placeholder.com/150?text=No+Image"; // תמונת ברירת מחדל
    }
    
    // אם זו תמונה חיצונית (http)
    if (img.startsWith('http')) {
        return img;
    }
    
    // אם זו תמונה מהשרת שלך
    return `http://localhost:8080/image/${img}`;
};
